SELECT alliance_name
FROM alliances
WHERE alliance_id = 1;

SELECT total_matches
FROM performance_stats
WHERE alliance_id = 1;

SELECT alliance_name, number_of_teams
FROM alliances
WHERE alliance_id = (SELECT alliance_id FROM teams WHERE team_name = 'Team Beta');

SELECT alliance_name, number_of_teams
FROM alliances
ORDER BY number_of_teams DESC;
